import{_ as t,o as i,c as o,ag as r}from"./chunks/framework.DUvHsH_U.js";const u=JSON.parse('{"title":"Product Catalog, Categories, Pricing, and Stock Availability Setup","description":"","frontmatter":{},"headers":[],"relativePath":"products-pricing/product-catalog-pricing-stock-setup.md","filePath":"products-pricing/product-catalog-pricing-stock-setup.md","lastUpdated":1777975835000}'),l={name:"products-pricing/product-catalog-pricing-stock-setup.md"};function s(a,e,n,c,g,h){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="product-catalog-categories-pricing-and-stock-availability-setup" tabindex="-1">Product Catalog, Categories, Pricing, and Stock Availability Setup <a class="header-anchor" href="#product-catalog-categories-pricing-and-stock-availability-setup" aria-label="Permalink to &quot;Product Catalog, Categories, Pricing, and Stock Availability Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup allows guests to browse visible product categories and catalog items in the mobile app. It also allows logged-in customers to see only the products that have a valid customer price and available quantity in the warehouse assigned to their territory.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Grant Guest users catalog access</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Role Permissions Manager</strong> and open it.</li><li>For each document type below, add or confirm a row for the <strong>Guest</strong> role.</li><li>Check <strong>Read</strong> only.</li><li>Click <strong>Save</strong> after each document type is updated.</li></ul><p>Required Guest Read permissions:</p><ul><li><strong>Item</strong></li><li><strong>Website Item</strong></li><li><strong>File</strong></li><li><strong>Item Category</strong></li></ul></li><li><p><strong>Grant Customer users catalog, pricing, stock, and profile access</strong></p><ul><li>Stay in <strong>Role Permissions Manager</strong>.</li><li>For each document type below, add or confirm a row for the <strong>Customer</strong> role.</li><li>Check <strong>Read</strong> only.</li><li>Click <strong>Save</strong> after each document type is updated.</li></ul><p>Required Customer Read permissions:</p><ul><li><strong>Item</strong></li><li><strong>Website Item</strong></li><li><strong>File</strong></li><li><strong>Item Category</strong></li><li><strong>Item Price</strong></li><li><strong>Bin</strong></li><li><strong>Customer</strong></li></ul></li><li><p><strong>Use the Mobile E-Commerce Control Panel if it is available</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Mobile E-Commerce Control Panel</strong> and open it.</li><li>If this page is available on the client&#39;s site, you can use it to manage catalog publishing faster.</li><li>From this page, create the required main categories.</li><li>Create the required subcategories under the correct main categories.</li><li>Publish the categories that should appear in the mobile app.</li><li>Publish the items that should appear in the mobile app.</li><li>Assign or publish the items under the correct categories.</li><li>Save your changes before testing in the mobile app.</li><li>If this page is not available, continue with the manual category and item steps below.</li></ul></li><li><p><strong>Create or activate the product category</strong></p><ul><li>Go to <strong>Item Category List</strong>.</li><li>Open the category that should appear in the mobile app.</li><li>Confirm the category is active and correctly named.</li><li>Check <strong>Show in Mobile Application</strong>.</li><li>If the category belongs under another category, confirm the parent category is selected correctly.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Enable and publish the item</strong></p><ul><li>Go to <strong>Item List</strong>.</li><li>Open the item that should appear in the mobile app.</li><li>Confirm the item is <strong>Enabled</strong>.</li><li>Confirm the item is assigned to the correct active <strong>Item Category</strong>.</li><li>Open the <strong>Actions</strong> drop-down.</li><li>Click <strong>Publish in Website</strong>.</li><li>Save the item if ERPNext asks you to save changes.</li></ul></li><li><p><strong>Select at least one mobile-visible UOM</strong></p><ul><li>Stay on the item document.</li><li>Scroll to the item&#39;s <strong>UOMs</strong> table.</li><li>Confirm at least one row exists.</li><li>In at least one UOM row, check <strong>Show in Mobile Application</strong>.</li><li>Confirm the UOM and conversion factor are correct for sales.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Confirm the item image is public</strong></p><ul><li>Stay on the item document.</li><li>Check the item image and the attachments area.</li><li>Open the uploaded image file.</li><li>Confirm the file is not marked as private.</li><li>If it is private, clear the private setting or upload the image again as a public file.</li><li>Save the file record and return to the item.</li></ul></li><li><p><strong>Set the customer&#39;s price list and territory</strong></p><ul><li>Go to <strong>Customer List</strong>.</li><li>Open the customer that is linked to the mobile user.</li><li>Confirm <strong>Default Price List</strong> is filled in.</li><li>Confirm <strong>Territory</strong> is selected.</li><li>Click <strong>Save</strong> if you make changes.</li></ul></li><li><p><strong>Assign a warehouse to the customer&#39;s territory</strong></p></li></ol><ul><li>Go to <strong>Territory List</strong>.</li><li>Open the same territory selected on the customer document.</li><li>Find the warehouse field used for mobile stock availability.</li><li>Select the correct <strong>Warehouse</strong>.</li><li>Click <strong>Save</strong>.</li></ul><ol start="11"><li><p><strong>Create or confirm the item price</strong></p><ul><li>Go to <strong>Item Price List</strong>.</li><li>Search for the item and the customer&#39;s default price list.</li><li>If a matching record exists, open it and confirm the price is correct.</li><li>If no matching record exists, click <strong>New</strong>.</li><li>Select the <strong>Item</strong>.</li><li>Select the same <strong>Price List</strong> used as the customer&#39;s Default Price List.</li><li>Enter the selling price.</li><li>Save the Item Price record.</li></ul></li><li><p><strong>Confirm stock is available in the assigned warehouse</strong></p><ul><li>Go to <strong>Bin List</strong>.</li><li>Filter by the item and the warehouse assigned to the customer&#39;s territory.</li><li>Confirm the actual quantity is greater than zero.</li><li>If the quantity is empty or zero, create a test stock entry: <ul><li>Go to <strong>Stock Entry List</strong>.</li><li>Click <strong>New</strong>.</li><li>Choose a stock entry purpose suitable for adding test quantity, such as <strong>Material Receipt</strong>.</li><li>Add the item.</li><li>Select the assigned warehouse.</li><li>Enter the test quantity.</li><li>Save and submit the stock entry.</li></ul></li><li>Return to <strong>Bin List</strong> and confirm the quantity is now available.</li></ul></li><li><p><strong>Test in the mobile app</strong></p><ul><li>Fully close and reopen the mobile app.</li><li>Without logging in, open the catalog.</li><li>Guest users should see the published categories and items with public images.</li><li>Log in as the customer.</li><li>Open the same category.</li><li>The customer should see items that have a valid price in their default price list and available quantity in the warehouse assigned to their territory.</li><li>Open an item details page and confirm the price, UOM, image, and availability appear correctly.</li></ul></li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ol><li><p><strong>If items do not appear at all</strong></p><ul><li>The item may not be published for website display.</li><li>Open the item, use <strong>Actions</strong>, and select <strong>Publish in Website</strong>.</li><li>The item may not be assigned to an active mobile category.</li><li>Open the category and confirm <strong>Show in Mobile Application</strong> is checked.</li><li>The item may not have any mobile-visible UOM.</li><li>Open the item&#39;s <strong>UOMs</strong> table and confirm at least one row has <strong>Show in Mobile Application</strong> checked.</li><li>The Guest or Customer role may be missing <strong>Read</strong> permission for catalog documents.</li></ul></li><li><p><strong>If items appear for guests but disappear after customer login</strong></p><ul><li>This usually means the customer-specific setup is incomplete.</li><li>Open the customer document and confirm <strong>Territory</strong> is selected.</li><li>Open the customer document and confirm <strong>Default Price List</strong> is filled in.</li><li>Open the selected territory and confirm a <strong>Warehouse</strong> is assigned.</li><li>Open <strong>Item Price List</strong> and confirm the item has a price for the customer&#39;s default price list.</li><li>Open <strong>Bin List</strong> and confirm the assigned warehouse has actual quantity greater than zero for the item.</li></ul></li><li><p><strong>If the app shows an empty category after login</strong></p><ul><li>The category may be correct, but no items inside it meet the customer rules.</li><li>Check each item in that category for a matching item price and positive stock in the customer&#39;s territory warehouse.</li><li>Also confirm the customer has a territory and that the territory has a warehouse.</li></ul></li><li><p><strong>If the price is missing or appears as zero</strong></p><ul><li>The item does not have a valid Item Price for the customer&#39;s Default Price List.</li><li>Open <strong>Customer List</strong>, confirm the customer&#39;s <strong>Default Price List</strong>.</li><li>Open <strong>Item Price List</strong>, create or correct the price record for that item and price list.</li><li>Save the record, then fully close and reopen the mobile app before testing again.</li></ul></li><li><p><strong>If the image is missing or broken in the app</strong></p><ul><li>Open the item in ERPNext.</li><li>Check the item&#39;s image and attachments.</li><li>Click the image link.</li><li>Confirm the image file actually opens in ERPNext.</li><li>Confirm the file is not marked as private.</li><li>If the file cannot be found, upload the image again.</li><li>If the file is private, make it public or replace it with a public upload.</li></ul></li><li><p><strong>If the customer sees fewer products than expected</strong></p><ul><li>The app only shows products that pass all customer checks.</li><li>Confirm every expected product is published, belongs to an active mobile category, has at least one mobile-visible UOM, has a matching item price, and has available quantity in the assigned warehouse.</li></ul></li></ol>',9)])])}const m=t(l,[["render",s]]);export{u as __pageData,m as default};
